// type from its container ID (".../class:Outer.Inner" -> "Inner").
func enclosingTypeShortName(from SymbolRecord) string {
	id := from.ContainerID
	if idx := strings.LastIndex(id, ":"); idx >= 0 {
		id = id[idx+1:]
	}
	if idx := strings.LastIndex(id, "."); idx >= 0 {
		id = id[idx+1:]
	}
	return id
}

